function renderGallery() {
  const catGrid = document.getElementById('catGrid');
  const dogGrid = document.getElementById('dogGrid');
  catGrid.innerHTML = ''; dogGrid.innerHTML = '';
  pets.forEach(p => {
    const card = document.createElement('div');
    card.className = 'card';
    card.addEventListener('click', function() { showDetail(p.id); });
    card.innerHTML = '<div class="card-avatar">' + p.emoji + '</div>' +
      '<div class="card-name">' + p.name + '</div>' +
      '<div class="card-breed">' + p.breed + '</div>' +
      '<div class="card-tag">' + (p.type === 'cat' ? '🐱 猫咪' : '🐶 狗狗') + '</div>';
    (p.type === 'cat' ? catGrid : dogGrid).appendChild(card);
  });
}

function showDetail(id) {
  var pet = pets.find(function(p) { return p.id === id; });
  if (!pet) return;
  document.getElementById('gallery').style.display = 'none';
  var detail = document.getElementById('detail');
  detail.style.display = 'block';
  detail.classList.add('active');
  document.getElementById('backBtn').style.display = 'block';

  var scoreHTML = '';
  var keys = Object.keys(pet.scores);
  for (var i = 0; i < keys.length; i++) {
    var k = keys[i], v = pet.scores[k];
    scoreHTML += '<div style="display:flex;align-items:center;gap:8px;margin:6px 0;">' +
      '<span style="width:36px;font-size:.85rem;font-weight:600;">' + k + '</span>' +
      '<div style="flex:1;height:8px;background:#eee;border-radius:4px;overflow:hidden;">' +
      '<div style="height:100%;width:' + (v*20) + '%;background:#f0a261;border-radius:4px;transition:width .6s;"></div>' +
      '</div>' +
      '<span style="font-size:.78rem;color:#8c7b6b;">' + v + '/5</span>' +
      '</div>';
  }

  var traitsHTML = '';
  for (var t = 0; t < pet.traits.length; t++) {
    traitsHTML += '<span class="tag">' + pet.traits[t] + '</span>';
  }

  var careHTML = '';
  for (var c = 0; c < pet.care.length; c++) {
    careHTML += '<li>' + pet.care[c] + '</li>';
  }

  detail.innerHTML =
    '<div class="detail-hero">' +
      '<div class="detail-emoji">' + pet.emoji + '</div>' +
      '<div class="detail-name">' + pet.name + '</div>' +
      '<div class="detail-breed">' + pet.breed + '</div>' +
      '<div class="badge-row">' +
        '<div class="badge"><div class="val">' + pet.origin + '</div><div class="lbl">原产地</div></div>' +
        '<div class="badge"><div class="val">' + pet.lifespan + '</div><div class="lbl">寿命</div></div>' +
        '<div class="badge"><div class="val">' + pet.weight + '</div><div class="lbl">体重</div></div>' +
      '</div>' +
    '</div>' +
    '<div class="info-card">' +
      '<h3>📖 品种介绍</h3>' +
      '<p>' + pet.desc + '</p>' +
      '<div class="tag-row">' + traitsHTML + '</div>' +
    '</div>' +
    '<div class="info-card">' +
      '<h3>📊 特性评分</h3>' +
      scoreHTML +
    '</div>' +
    '<div class="info-card">' +
      '<h3>🛁 饲养指南</h3>' +
      '<ul>' + careHTML + '</ul>' +
    '</div>' +
    '<button class="btn-home" id="btnHome">← 返回宠物列表</button>';
}

function goHome() {
  document.getElementById('gallery').style.display = 'block';
  document.getElementById('detail').style.display = 'none';
  document.getElementById('detail').classList.remove('active');
  document.getElementById('backBtn').style.display = 'none';
  window.location.hash = '';
  window.scrollTo({top: 0, behavior: 'smooth'});
}

document.getElementById('backBtn').addEventListener('click', goHome);
document.addEventListener('click', function(e) {
  if (e.target && e.target.id === 'btnHome') goHome();
});

function handleRoute() {
  var hash = window.location.hash.slice(1);
