content = r'''<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>🐾 萌宠之家 — 遇见你的灵魂伙伴</title>
<style>
/* ===== CSS Variables ===== */
:root {
  --bg: #faf7f2;
  --surface: #ffffff;
  --surface-glass: rgba(255,255,255,0.72);
  --text: #3a2c1e;
  --muted: #8c7b6b;
  --accent: #f0a261;
  --accent2: #e07b5a;
  --accent3: #f7c873;
  --cat-gradient: linear-gradient(135deg, #fce4d6 0%, #f8c9a8 100%);
  --dog-gradient: linear-gradient(135deg, #d4e0f0 0%, #b8c9e0 100%);
  --hero-gradient: linear-gradient(160deg, #fef5e7 0%, #fdebd0 30%, #fadbd8 70%, #e8d5f5 100%);
  --shadow-sm: 0 2px 8px rgba(0,0,0,.04);
  --shadow: 0 4px 24px rgba(0,0,0,.06);
  --shadow-lg: 0 12px 40px rgba(0,0,0,.1);
  --radius: 18px;
  --radius-sm: 12px;
  --transition: 0.3s cubic-bezier(.4,0,.2,1);
  --bounce: 0.4s cubic-bezier(.34,1.56,.64,1);
}

/* ===== Reset ===== */
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{
  font-family:"PingFang SC","Microsoft YaHei","Noto Sans SC",system-ui,sans-serif;
  background:var(--bg);color:var(--text);min-height:100vh;line-height:1.7;
  overflow-x:hidden;
  position:relative;
}

/* ===== Floating Background Particles ===== */
.particles{position:fixed;inset:0;pointer-events:none;z-index:0;overflow:hidden}
.particle{
  position:absolute;font-size:1.6rem;opacity:0.18;
  animation:floatUp linear infinite;
}
@keyframes floatUp{
  0%{transform:translateY(105vh) rotate(0deg);opacity:0}
  10%{opacity:0.2}
  90%{opacity:0.18}
  100%{transform:translateY(-10vh) rotate(360deg);opacity:0}
}

/* ===== Hero Banner ===== */
.hero{
  position:relative;z-index:1;
  background:var(--hero-gradient);
  padding:60px 20px 50px;text-align:center;
  clip-path:ellipse(120% 100% at 50% 0%);
  margin-bottom:-20px;
}
.hero::after{
  content:'';position:absolute;inset:0;
  background:radial-gradient(circle at 30% 40%,rgba(255,255,255,0.4) 0%,transparent 50%),
             radial-gradient(circle at 70% 60%,rgba(255,200,150,0.25) 0%,transparent 50%);
  pointer-events:none;
}
.hero-badge{
  display:inline-block;background:rgba(255,255,255,0.7);backdrop-filter:blur(10px);
  padding:6px 20px;border-radius:20px;font-size:.85rem;color:var(--accent2);
  font-weight:600;margin-bottom:16px;letter-spacing:1px;
}
.hero h1{font-size:2.8rem;font-weight:800;letter-spacing:3px;position:relative;z-index:1}
.hero h1 .wave{display:inline-block;animation:wave 2s ease-in-out infinite}
.hero h1 .wave:nth-child(1){animation-delay:0s}
.hero h1 .wave:nth-child(2){animation-delay:.15s}
.hero h1 .wave:nth-child(3){animation-delay:.3s}
@keyframes wave{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}
.hero .subtitle{
  color:var(--muted);font-size:1.05rem;margin-top:8px;position:relative;z-index:1;
}
.hero .subtitle span{color:var(--accent2);font-weight:600}

/* ===== Filter Tabs ===== */
.filter-bar{
  position:relative;z-index:2;
  display:flex;justify-content:center;gap:10px;margin:0 auto 28px;flex-wrap:wrap;
  max-width:600px;padding:0 20px;
}
.filter-btn{
  background:var(--surface-glass);backdrop-filter:blur(16px);
  border:1.5px solid rgba(0,0,0,.06);padding:10px 26px;border-radius:24px;
  cursor:pointer;font-size:.92rem;font-weight:600;color:var(--muted);
  transition:all var(--transition);position:relative;overflow:hidden;
}
.filter-btn::after{
  content:'';position:absolute;inset:0;background:var(--accent);
  transform:scaleX(0);transform-origin:left;transition:transform var(--transition);z-index:-1;
}
.filter-btn.active::after{transform:scaleX(1)}
.filter-btn.active{color:#fff;border-color:transparent;box-shadow:0 4px 15px rgba(240,162,97,.35)}
.filter-btn:hover:not(.active){border-color:var(--accent);color:var(--accent2);transform:translateY(-2px)}
.filter-btn .count{
  display:inline-block;background:rgba(0,0,0,.06);border-radius:10px;
  padding:1px 8px;font-size:.72rem;margin-left:6px;
}
.filter-btn.active .count{background:rgba(255,255,255,.25)}

/* ===== Main Container ===== */
.container{position:relative;z-index:1;max-width:1100px;margin:0 auto;padding:0 20px 60px}

/* ===== Grid ===== */
.grid{
  display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));
  gap:20px;margin-bottom:36px;
}

/* ===== Card (Glass Morphism + 3D Tilt) ===== */
.card{
  perspective:800px;height:280px;
  opacity:0;transform:translateY(40px);
  animation:cardEnter 0.6s var(--bounce) forwards;
}
.card-inner{
  position:relative;width:100%;height:100%;
  background:var(--surface-glass);backdrop-filter:blur(20px);
  border-radius:var(--radius);border:1px solid rgba(255,255,255,0.6);
  box-shadow:var(--shadow);cursor:pointer;
  transition:all var(--transition);
  display:flex;flex-direction:column;align-items:center;
  overflow:hidden;text-align:center;
}
.card-inner:hover{
  transform:translateY(-8px) scale(1.02);
  box-shadow:var(--shadow-lg);
  border-color:var(--accent);
}
.card-inner:active{transform:translateY(-4px) scale(0.98);transition:.1s}
.card-glow{
  position:absolute;top:0;left:0;right:0;height:3px;
  background:linear-gradient(90deg,transparent,var(--accent),var(--accent3),var(--accent),transparent);
  background-size:200% 100%;animation:shimmer 3s ease-in-out infinite;
  opacity:0;transition:opacity .3s;
}
.card-inner:hover .card-glow{opacity:1}
@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}
.card-emoji-ring{
  width:90px;height:90px;border-radius:50%;
  display:flex;align-items:center;justify-content:center;
  margin-top:24px;font-size:3.2rem;
  position:relative;z-index:1;
  animation:pulse 2s ease-in-out infinite;
}
.card-emoji-ring::before{
  content:'';position:absolute;inset:-6px;border-radius:50%;
  border:2px dashed rgba(240,162,97,.25);animation:spin 12s linear infinite;
}
@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.06)}}
@keyframes spin{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}
.card-name{font-size:1.15rem;font-weight:700;margin-top:12px;position:relative;z-index:1}
.card-breed{font-size:.8rem;color:var(--muted);margin-top:2px;position:relative;z-index:1}
.card-tags{display:flex;gap:6px;margin-top:10px;flex-wrap:wrap;justify-content:center;position:relative;z-index:1}
.card-tag{
  font-size:.68rem;padding:3px 10px;border-radius:10px;
  background:rgba(240,162,97,.12);color:var(--accent2);font-weight:600;
}
.card-badge{
  position:absolute;top:12px;right:12px;z-index:2;
  font-size:.7rem;padding:3px 10px;border-radius:10px;
  font-weight:700;letter-spacing:.5px;
}
.card-badge.cat{background:rgba(232,168,124,.2);color:#c07a4a}
.card-badge.dog{background:rgba(180,160,200,.2);color:#6b5b8a}

/* Staggered card entrance */
@keyframes cardEnter{to{opacity:1;transform:translateY(0)}}

/* ===== Detail Page ===== */
.detail-overlay{
  display:none;position:fixed;inset:0;background:rgba(0,0,0,.35);
  z-index:200;backdrop-filter:blur(4px);
  animation:fadeIn .3s ease;
}
.detail-overlay.active{display:block}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
.detail-panel{
  display:none;position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);
  z-index:300;width:min(700px,94vw);max-height:88vh;overflow-y:auto;
  background:var(--surface);border-radius:24px;
  box-shadow:0 20px 60px rgba(0,0,0,.18);
  animation:panelIn .4s var(--bounce);
  padding:0;
}
.detail-panel.active{display:block}
@keyframes panelIn{from{opacity:0;transform:translate(-50%,-50%) scale(.9) translateY(20px)}to{opacity:1;transform:translate(-50%,-50%) scale(1) translateY(0)}}

.detail-header{
  position:relative;padding:32px 28px 20px;text-align:center;
  border-radius:24px 24px 0 0;
}
.detail-header.cat-bg{background:linear-gradient(180deg,#fef5eb 0%,#fff 100%)}
.detail-header.dog-bg{background:linear-gradient(180deg,#f0f3fa 0%,#fff 100%)}
.detail-close{
  position:absolute;top:16px;right:20px;width:36px;height:36px;
