.detail-close:hover{background:rgba(0,0,0,.12);transform:rotate(90deg)}
.detail-emoji-big{font-size:5.5rem;animation:bounceIn .5s var(--bounce)}
@keyframes bounceIn{0%{transform:scale(0);opacity:0}60%{transform:scale(1.15)}100%{transform:scale(1);opacity:1}}
.detail-name-big{font-size:2rem;font-weight:800;margin-top:4px}
.detail-breed-name{color:var(--muted);font-size:.95rem;margin-bottom:8px}

/* Badge stats row */
.stat-row{display:flex;gap:12px;justify-content:center;flex-wrap:wrap;margin:12px 0 0}
.stat-item{
  background:rgba(240,162,97,.08);border-radius:14px;
