/* Score bar */
.score-bar{margin:8px 0;display:flex;align-items:center;gap:10px}
.score-label{width:40px;font-size:.82rem;font-weight:600;text-align:right}
.score-track{flex:1;height:10px;background:#eee;border-radius:5px;overflow:hidden}
.score-fill{height:100%;background:linear-gradient(90deg,var(--accent3),var(--accent));border-radius:5px;width:0;transition:width 1s var(--bounce)}
.score-val{font-size:.78rem;color:var(--muted);width:28px}

.care-list{list-style:none;padding:0}
.care-list li{
  padding:8px 14px;margin:6px 0;background:rgba(240,162,97,.05);
  border-radius:10px;font-size:.88rem;color:var(--muted);
