  transition:all var(--transition);
}
.care-list li:hover{background:rgba(240,162,97,.12);transform:translateX(4px)}
.care-list li::before{content:'🐾';font-size:.8rem}

.sound-toggle{
  position:fixed;bottom:24px;right:24px;z-index:500;
  width:48px;height:48px;border-radius:50%;
  background:var(--surface-glass);backdrop-filter:blur(16px);
  border:1.5px solid rgba(0,0,0,.08);cursor:pointer;
