    desc:'哈士奇，二哈、拆迁办主任——外表像狼，灵魂是喜剧演员。精力极度旺盛，拥有独特的"狼嚎"技能。个性友善但服从性差，需要极大的运动量和耐心。',
    traits:['精力旺盛','狼嚎技能','友善神经质','表情包担当'],
    scores:{亲和:5,运动:5,掉毛:4,聪明:2},
    care:['每天大量运动（跑步/拉车）','坚固的围栏（越狱大师）','注意夏季防暑','家里值钱物品收好'],
    origin:'俄罗斯（西伯利亚）',lifespan:'12-15年',weight:'16-27 kg' },
  { id:'poodle',type:'dog',name:'泰迪（贵宾）',breed:'Toy Poodle',emoji:'🐩',
    desc:'泰迪其实是贵宾犬的一种美容造型。智商排名第二（狗界），几乎不掉毛，体味极轻，是过敏人士和公寓住户的绝佳选择。活泼粘人，擅长各种才艺表演。',
    traits:['智商高','不掉毛','活泼粘人','体味轻'],
    scores:{亲和:5,运动:3,掉毛:1,聪明:5},
    care:['每 4-6 周专业美容','每天梳毛防止毛结','提供益智互动玩具','注意泪痕和牙齿清洁'],
    origin:'法国/德国',lifespan:'12-15年',weight:'2-4 kg' },
  { id:'shiba',type:'dog',name:'柴犬',breed:'Shiba Inu',emoji:'🦊',
    desc:'Doge 本尊——柴犬凭借魔性微笑火遍全球。性格独立骄傲，像猫一样自我。忠诚但固执，有自己的小脾气。天生爱干净，会自己打理毛发。',
    traits:['网红微笑','独立骄傲','爱干净','倔强固执'],
    scores:{亲和:3,运动:3,掉毛:3,聪明:4},
    care:['出门必须牵绳（撒手没）','定期梳毛（换毛季大量掉毛）','尊重它的独立空间','从小社会化训练'],
    origin:'日本',lifespan:'12-16年',weight:'8-11 kg' },
];

// ============================
//  AUDIO ENGINE (Web Audio API)
// ============================
let audioCtx = null;
let soundEnabled = true;

function getAudioCtx() {
  if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  if (audioCtx.state === 'suspended') audioCtx.resume();
  return audioCtx;
}

function playTone(freq, type, duration, vol, ramp) {
  if (!soundEnabled) return;
  try {
    const ctx = getAudioCtx();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, ctx.currentTime);
    if (ramp) osc.frequency.linearRampToValueAtTime(ramp, ctx.currentTime + duration);
    gain.gain.setValueAtTime(vol, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + duration);
  } catch(e) {}
}

// Click sound
function sfxClick() {
  playTone(800, 'sine', 0.08, 0.15, 1200);
}

// Hover sound (gentle chime)
function sfxHover() {
  playTone(1200, 'sine', 0.06, 0.06, null);
  setTimeout(function(){ playTone(1600, 'sine', 0.06, 0.05, null); }, 40);
}

// Open panel sound
function sfxOpen() {
  playTone(500, 'sine', 0.1, 0.12, 900);
  setTimeout(function(){ playTone(700, 'sine', 0.1, 0.1, null); }, 60);
  setTimeout(function(){ playTone(1000, 'sine', 0.12, 0.08, null); }, 120);
}

// Close panel sound
function sfxClose() {
  playTone(600, 'sine', 0.08, 0.1, 300);
}

// Meow sound (cat)
function sfxMeow() {
  const ctx = getAudioCtx();
  if (!soundEnabled) return;
  try {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(400, ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(600, ctx.currentTime + 0.08);
    osc.frequency.linearRampToValueAtTime(500, ctx.currentTime + 0.2);
    osc.frequency.linearRampToValueAtTime(700, ctx.currentTime + 0.28);
    osc.frequency.linearRampToValueAtTime(400, ctx.currentTime + 0.4);
    gain.gain.setValueAtTime(0.2, ctx.currentTime);
    gain.gain.linearRampToValueAtTime(0.25, ctx.currentTime + 0.05);
    gain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + 0.3);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.5);
  } catch(e) {}
}

// Bark sound (dog)
function sfxBark() {
  const ctx = getAudioCtx();
  if (!soundEnabled) return;
  try {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(180, ctx.currentTime);
    osc.frequency.linearRampToValueAtTime(300, ctx.currentTime + 0.05);
    osc.frequency.linearRampToValueAtTime(120, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(0.18, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 0.25);

    setTimeout(function() {
      const o2 = ctx.createOscillator();
      const g2 = ctx.createGain();
      o2.type = 'sawtooth';
      o2.frequency.setValueAtTime(140, ctx.currentTime);
      o2.frequency.linearRampToValueAtTime(220, ctx.currentTime + 0.04);
      g2.gain.setValueAtTime(0.12, ctx.currentTime);
      g2.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);
      o2.connect(g2);
      g2.connect(ctx.destination);
      o2.start(ctx.currentTime);
      o2.stop(ctx.currentTime + 0.15);
    }, 100);
  } catch(e) {}
}

// ============================
//  FLOATING PARTICLES
// ============================
function createParticles() {
  const container = document.getElementById('particles');
  const icons = ['🐾','✦','❤','🐱','🐶','🐕','🐩','🐈','🐈‍⬛','🦴','🧶','🎾','💕'];
  for (let i = 0; i < 20; i++) {
    const p = document.createElement('div');
    p.className = 'particle';
    p.textContent = icons[Math.floor(Math.random() * icons.length)];
    p.style.left = Math.random() * 100 + '%';
    p.style.fontSize = (1 + Math.random() * 2.5) + 'rem';
    p.style.animationDuration = (12 + Math.random() * 20) + 's';
    p.style.animationDelay = Math.random() * 15 + 's';
    container.appendChild(p);
  }
}

// ============================
//  RENDER GALLERY
// ============================
let currentFilter = 'all';

function renderGallery(filter) {
  currentFilter = filter || 'all';
  const grid = document.getElementById('petGrid');
  grid.innerHTML = '';
  const filtered = currentFilter === 'all' ? pets : pets.filter(function(p){ return p.type === currentFilter; });

  filtered.forEach(function(pet, index) {
    const card = document.createElement('div');
    card.className = 'card';
    card.style.animationDelay = (index * 0.06) + 's';
    card.innerHTML =
      '<div class="card-inner">' +
        '<div class="card-glow"></div>' +
        '<span class="card-badge ' + pet.type + '">' + (pet.type === 'cat' ? '🐱' : '🐶') + '</span>' +
        '<div class="card-emoji-ring">' + pet.emoji + '</div>' +
        '<div class="card-name">' + pet.name + '</div>' +
        '<div class="card-breed">' + pet.breed + '</div>' +
        '<div class="card-tags">' +
          '<span class="card-tag">' + pet.traits[0] + '</span>' +
          '<span class="card-tag">' + pet.traits[1] + '</span>' +
        '</div>' +
      '</div>';

    card.addEventListener('click', function() {
      sfxClick();
      if (pet.type === 'cat') sfxMeow();
      else sfxBark();
      showDetail(pet);
    });
    card.addEventListener('mouseenter', function(){ sfxHover(); });

    grid.appendChild(card);
  });
}

// ============================
//  SHOW DETAIL
// ============================
function showDetail(pet) {
  sfxOpen();
  const overlay = document.getElementById('detailOverlay');
  const panel = document.getElementById('detailPanel');

  var scoreHTML = '';
  var keys = Object.keys(pet.scores);
  for (var i = 0; i < keys.length; i++) {
    var k = keys[i], v = pet.scores[k];
    scoreHTML +=
      '<div class="score-bar">' +
        '<span class="score-label">' + k + '</span>' +
        '<div class="score-track"><div class="score-fill" data-width="' + (v * 20) + '"></div></div>' +
        '<span class="score-val">' + v + '/5</span>' +
      '</div>';
  }

  var traitsHTML = '';
  for (var t = 0; t < pet.traits.length; t++) {
    traitsHTML += '<span class="tag-chic">' + pet.traits[t] + '</span>';
  }

  var careHTML = '';
  for (var c = 0; c < pet.care.length; c++) {
    careHTML += '<li>' + pet.care[c] + '</li>';
  }

  panel.innerHTML =
    '<div class="detail-header ' + (pet.type === 'cat' ? 'cat-bg' : 'dog-bg') + '">' +
      '<button class="detail-close" id="detailClose">✕</button>' +
      '<div class="detail-emoji-big">' + pet.emoji + '</div>' +
      '<div class="detail-name-big">' + pet.name + '</div>' +
      '<div class="detail-breed-name">' + pet.breed + '</div>' +
      '<div class="stat-row">' +
        '<div class="stat-item"><div class="stat-val">' + pet.origin + '</div><div class="stat-lbl">原产地</div></div>' +
        '<div class="stat-item"><div class="stat-val">' + pet.lifespan + '</div><div class="stat-lbl">寿命</div></div>' +
        '<div class="stat-item"><div class="stat-val">' + pet.weight + '</div><div class="stat-lbl">体重</div></div>' +
      '</div>' +
    '</div>' +
    '<div class="detail-body">' +
      '<div class="info-section">' +
        '<h3>📖 品种介绍</h3>' +
        '<p>' + pet.desc + '</p>' +
        '<div class="tags-line">' + traitsHTML + '</div>' +
      '</div>' +
      '<div class="info-section">' +
        '<h3>📊 特性评分</h3>' +
        scoreHTML +
      '</div>' +
      '<div class="info-section">' +
        '<h3>🛁 饲养指南</h3>' +
        '<ul class="care-list">' + careHTML + '</ul>' +
      '</div>' +
    '</div>';

  overlay.classList.add('active');
  panel.classList.add('active');
  document.body.style.overflow = 'hidden';

  // Animate score bars after a short delay
  setTimeout(function() {
    var fills = panel.querySelectorAll('.score-fill');
    for (var f = 0; f < fills.length; f++) {
      setTimeout(function(idx) {
        fills[idx].style.width = fills[idx].getAttribute('data-width') + '%';
      }, f * 100, f);
    }
  }, 350);

  // Close events
  document.getElementById('detailClose').addEventListener('click', closeDetail);
  overlay.addEventListener('click', closeDetail);
  document.addEventListener('keydown', function escHandler(e) {
    if (e.key === 'Escape') { closeDetail(); document.removeEventListener('keydown', escHandler); }
  });
}

function closeDetail() {
  sfxClose();
  document.getElementById('detailOverlay').classList.remove('active');
  document.getElementById('detailPanel').classList.remove('active');
  document.body.style.overflow = '';
}

// ============================
//  FILTER TABS
// ============================
var filterBtns = document.querySelectorAll('.filter-btn');
for (var b = 0; b < filterBtns.length; b++) {
  filterBtns[b].addEventListener('click', function() {
    sfxClick();
    filterBtns.forEach(function(btn){ btn.classList.remove('active'); });
    this.classList.add('active');
    renderGallery(this.getAttribute('data-filter'));
  });
}

// ============================
//  SOUND TOGGLE
// ============================
document.getElementById('soundToggle').addEventListener('click', function() {
  soundEnabled = !soundEnabled;
  this.textContent = soundEnabled ? '🔊' : '🔇';
  if (soundEnabled) { this.classList.remove('muted'); }
  else { this.classList.add('muted'); sfxClick(); }
});

// ============================
//  INIT
// ============================
createParticles();
renderGallery('all');
</script>
</body>
</html>'''

