content = r'''<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CryptoSight — 实时加密货币监控</title>
<style>
:root {
  --bg0: #0d1117;
  --bg1: #161b22;
  --bg2: #1c2333;
  --border: #30363d;
  --text: #e6edf3;
  --muted: #8b949e;
  --green: #26a69a;
  --red: #ef5350;
  --accent: #58a6ff;
  --accent2: #7c3aed;
  --radius: 12px;
  --radius-sm: 8px;
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{
  font-family:"SF Mono","JetBrains Mono","Cascadia Code","Consolas","Microsoft YaHei",monospace;
  background:var(--bg0);color:var(--text);min-height:100vh;
  overflow-x:hidden;
}
a{color:var(--accent);text-decoration:none}

/* ===== HEADER ===== */
.header{
  background:var(--bg1);border-bottom:1px solid var(--border);
  padding:14px 24px;display:flex;align-items:center;justify-content:space-between;
  position:sticky;top:0;z-index:100;gap:16px;flex-wrap:wrap;
  backdrop-filter:blur(12px);
}
.header-left{display:flex;align-items:center;gap:12px}
.logo{font-size:1.3rem;font-weight:800;letter-spacing:1px;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.status-dot{width:8px;height:8px;border-radius:50%;background:var(--green);animation:blink 1.5s ease-in-out infinite}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.3}}
.status-text{font-size:.72rem;color:var(--green)}
.header-right{display:flex;align-items:center;gap:12px;flex-wrap:wrap}

/* Search */
.search-wrap{position:relative}
.search-input{
  background:var(--bg2);border:1px solid var(--border);border-radius:20px;
  padding:8px 16px 8px 36px;color:var(--text);font-size:.82rem;width:200px;
  outline:none;transition:all .25s;font-family:inherit;
}
.search-input:focus{border-color:var(--accent);width:260px;box-shadow:0 0 0 3px rgba(88,166,255,.1)}
.search-icon{position:absolute;left:12px;top:50%;transform:translateY(-50%);font-size:.75rem;color:var(--muted);pointer-events:none}

/* Sort buttons */
.sort-group{display:flex;gap:4px}
.sort-btn{
  background:var(--bg2);border:1px solid var(--border);color:var(--muted);
  padding:7px 14px;border-radius:6px;cursor:pointer;font-size:.75rem;
  transition:all .2s;font-family:inherit;white-space:nowrap;
}
.sort-btn:hover{color:var(--text);border-color:var(--accent)}
.sort-btn.active{background:var(--accent);color:#fff;border-color:var(--accent)}

.refresh-indicator{font-size:.7rem;color:var(--muted);display:flex;align-items:center;gap:6px}
.countdown{color:var(--accent);font-weight:600;min-width:20px;text-align:center}

/* ===== TICKER TAPE ===== */
.ticker-tape{
  background:var(--bg1);border-bottom:1px solid var(--border);
  overflow:hidden;padding:8px 0;position:relative;
}
.ticker-track{
  display:flex;gap:32px;animation:scroll linear infinite;
  white-space:nowrap;width:max-content;
}
@keyframes scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}
.ticker-item{display:inline-flex;align-items:center;gap:6px;font-size:.78rem}
.ticker-symbol{font-weight:700;color:var(--text)}
.ticker-price{color:var(--muted)}
.ticker-change{font-weight:600}
.ticker-change.up{color:var(--green)}
.ticker-change.down{color:var(--red)}

/* ===== MAIN GRID ===== */
.container{max-width:1400px;margin:0 auto;padding:20px;display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:16px}
@media(max-width:680px){.container{grid-template-columns:1fr}}

/* ===== PRICE CARD ===== */
.card{
  background:var(--bg1);border:1px solid var(--border);border-radius:var(--radius);
  padding:18px 20px;cursor:pointer;transition:all .25s;
  position:relative;overflow:hidden;
}
.card:hover{border-color:var(--accent);transform:translateY(-2px);box-shadow:0 8px 30px rgba(0,0,0,.3)}
.card.flash-green{animation:flashG .6s ease}
.card.flash-red{animation:flashR .6s ease}
@keyframes flashG{0%{background:rgba(38,166,154,.15)}100%{background:transparent}}
@keyframes flashR{0%{background:rgba(239,83,80,.15)}100%{background:transparent}}

.card-top{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px}
.coin-info{display:flex;align-items:center;gap:10px}
.coin-icon{
  width:40px;height:40px;border-radius:50%;display:flex;align-items:center;justify-content:center;
  font-size:1.3rem;font-weight:800;background:var(--bg2);
}
.coin-symbol{font-size:.95rem;font-weight:700;color:var(--text)}
.coin-name{font-size:.7rem;color:var(--muted);margin-top:1px}
.coin-rank{font-size:.65rem;color:var(--muted);background:var(--bg2);padding:2px 8px;border-radius:4px}

.card-price{font-size:1.5rem;font-weight:800;font-variant-numeric:tabular-nums;margin-bottom:6px}
.card-change{font-size:.85rem;font-weight:600;margin-bottom:4px}
.card-change.up{color:var(--green)}
.card-change.down{color:var(--red)}

.card-bottom{display:flex;justify-content:space-between;font-size:.7rem;color:var(--muted);margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}
.card-bottom span{display:flex;flex-direction:column;gap:2px}
.card-bottom .lbl{font-size:.65rem;text-transform:uppercase;letter-spacing:.5px}
.card-bottom .val{color:var(--text);font-weight:600}

/* ===== SPARKLINE ===== */
.sparkline-wrap{height:48px;margin:8px 0 0}
.sparkline-wrap canvas{width:100%;height:100%}

/* ===== FOOTER ===== */
.footer{
  text-align:center;padding:24px;color:var(--muted);font-size:.72rem;
  border-top:1px solid var(--border);margin-top:20px;
}
.footer a{color:var(--accent)}

/* ===== LOADING ===== */
.loading{text-align:center;padding:60px;color:var(--muted);grid-column:1/-1}
.spinner{width:32px;height:32px;border:3px solid var(--border);border-top-color:var(--accent);border-radius:50%;animation:spin .8s linear infinite;margin:0 auto 12px}
@keyframes spin{to{transform:rotate(360deg)}}
.error-msg{color:var(--red);text-align:center;padding:20px;grid-column:1/-1}

/* ===== TOOLTIP ===== */
.tooltip{display:none;position:fixed;background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 14px;font-size:.75rem;z-index:200;pointer-events:none;box-shadow:0 8px 24px rgba(0,0,0,.4)}
</style>
</head>
<body>

<!-- HEADER -->
<header class="header">
  <div class="header-left">
    <div class="status-dot" id="statusDot"></div>
    <span class="logo">CryptoSight</span>
    <span class="status-text" id="statusText">实时连接中...</span>
  </div>
  <div class="header-right">
    <div class="search-wrap">
      <span class="search-icon">🔍</span>
      <input class="search-input" id="searchInput" placeholder="搜索币种..." autocomplete="off">
    </div>
    <div class="sort-group">
      <button class="sort-btn active" data-sort="rank">排名</button>
      <button class="sort-btn" data-sort="change">涨跌幅</button>
      <button class="sort-btn" data-sort="volume">交易量</button>
    </div>
    <div class="refresh-indicator">
      <span>刷新</span>
      <span class="countdown" id="countdown">5s</span>
    </div>
  </div>
</header>

<!-- TICKER TAPE -->
<div class="ticker-tape" id="tickerTape">
  <div class="ticker-track" id="tickerTrack"></div>
</div>

<!-- MAIN GRID -->
<div class="container" id="mainGrid">
  <div class="loading"><div class="spinner"></div><div>正在加载市场数据...</div></div>
</div>

<!-- FOOTER -->
<div class="footer">
  CryptoSight · 数据来源 <a href="https://coincap.io" target="_blank">CoinCap</a> &amp; <a href="https://binance.com" target="_blank">Binance</a> · 数据仅供参考
</div>

<script>
// ============================
//  CONFIG
// ============================
const MONITORED = [
  { id:'bitcoin',      symbol:'BTC',  name:'Bitcoin',           binance:'btcusdt' },
  { id:'ethereum',     symbol:'ETH',  name:'Ethereum',          binance:'ethusdt' },
  { id:'binance-coin', symbol:'BNB',  name:'BNB',               binance:'bnbusdt' },
  { id:'solana',       symbol:'SOL',  name:'Solana',            binance:'solusdt' },
  { id:'xrp',          symbol:'XRP',  name:'XRP',               binance:'xrpusdt' },
  { id:'cardano',      symbol:'ADA',  name:'Cardano',           binance:'adausdt' },
  { id:'dogecoin',     symbol:'DOGE', name:'Dogecoin',          binance:'dogeusdt' },
  { id:'avalanche',    symbol:'AVAX', name:'Avalanche',         binance:'avaxusdt' },
  { id:'polkadot',     symbol:'DOT',  name:'Polkadot',          binance:'dotusdt' },
  { id:'tron',         symbol:'TRX',  name:'TRON',              binance:'trxusdt' },
  { id:'polygon',      symbol:'MATIC',name:'Polygon',           binance:'maticusdt' },
  { id:'chainlink',    symbol:'LINK', name:'Chainlink',         binance:'linkusdt' },
  { id:'uniswap',      symbol:'UNI',  name:'Uniswap',           binance:'uniusdt' },
  { id:'litecoin',     symbol:'LTC',  name:'Litecoin',          binance:'ltcusdt' },
  { id:'bitcoin-cash', symbol:'BCH',  name:'Bitcoin Cash',      binance:'bchusdt' },
  { id:'cosmos',       symbol:'ATOM', name:'Cosmos',            binance:'atomusdt' },
  { id:'near-protocol',symbol:'NEAR', name:'NEAR Protocol',     binance:'nearusdt' },
  { id:'aptos',        symbol:'APT',  name:'Aptos',             binance:'aptusdt' },
  { id:'arbitrum',     symbol:'ARB',  name:'Arbitrum',          binance:'arbusdt' },
  { id:'optimism',     symbol:'OP',   name:'Optimism',          binance:'opusdt' },
  { id:'filecoin',     symbol:'FIL',  name:'Filecoin',          binance:'filusdt' },
  { id:'stellar',      symbol:'XLM',  name:'Stellar',           binance:'xlmusdt' },
  { id:'hedera',       symbol:'HBAR', name:'Hedera',            binance:'hbarusdt' },
  { id:'sui',          symbol:'SUI',  name:'Sui',               binance:'suiusdt' },
];

let coinData = {};           // id -> { price, change24h, marketCap, volume24h, sparkline }
let binancePrices = {};      // symbol -> lastPrice
let ws = null;
let searchQuery = '';
let sortBy = 'rank';
let refreshCountdown = 5;
let countdownTimer = null;

// ============================
//  FETCH COINCAP DATA
// ============================
async function fetchCoinCap() {
  try {
    const ids = MONITORED.map(function(c){ return c.id; }).join(',');
    const resp = await fetch('https://api.coincap.io/v2/assets?ids=' + ids + '&limit=50');
    if (!resp.ok) throw new Error('HTTP ' + resp.status);
    const json = await resp.json();
    json.data.forEach(function(a){
      coinData[a.id] = {
        price: parseFloat(a.priceUsd),
        change24h: parseFloat(a.changePercent24Hr),
        marketCap: parseFloat(a.marketCapUsd),
        volume24h: parseFloat(a.volumeUsd24Hr),
        rank: parseInt(a.rank),
        symbol: a.symbol,
        name: a.name,
        sparkline: coinData[a.id] ? coinData[a.id].sparkline : [],
      };
      // Track sparkline
      if (!coinData[a.id].sparkline) coinData[a.id].sparkline = [];
      coinData[a.id].sparkline.push(parseFloat(a.priceUsd));
      if (coinData[a.id].sparkline.length > 60) coinData[a.id].sparkline.shift();
    });
    renderAll();
    document.getElementById('statusText').textContent = '实时';
  } catch(e) {
    console.warn('CoinCap fetch failed:', e.message);
    document.getElementById('statusText').textContent = 'REST 离线';
    // Still render whatever we have from WebSocket
    renderAll();
  }
}

// ============================
//  BINANCE WEBSOCKET
// ============================
function connectBinanceWS() {
  if (ws) { ws.close(); }
  const streams = MONITORED.map(function(c){ return c.binance + '@miniTicker'; });
  const url = 'wss://stream.binance.com:9443/stream?streams=' + streams.join('/');

  ws = new WebSocket(url);
  ws.onopen = function() {
    document.getElementById('statusDot').style.background = 'var(--green)';
    document.getElementById('statusText').textContent = '实时';
    console.log('Binance WS connected');
  };
  ws.onmessage = function(e) {
    try {
      const msg = JSON.parse(e.data);
      if (msg.data) {
        const ticker = msg.data;
        const usdtSymbol = ticker.s.toUpperCase().replace('USDT', '');
        binancePrices[usdtSymbol] = parseFloat(ticker.c);
        // Update coinData price for monitored coins
        MONITORED.forEach(function(c){
          if (c.symbol === usdtSymbol && coinData[c.id]) {
            const oldPrice = coinData[c.id].price;
            coinData[c.id].price = parseFloat(ticker.c);
            // Track sparkline
            if (coinData[c.id].price !== oldPrice) {
              coinData[c.id].sparkline.push(coinData[c.id].price);
              if (coinData[c.id].sparkline.length > 60) coinData[c.id].sparkline.shift();
            }
          }
        });
        updateTicker();
        // Throttle full re-render
        if (!window._renderTimeout) {
          window._renderTimeout = setTimeout(function(){
            renderAll();
            window._renderTimeout = null;
          }, 400);
        }
      }
    } catch(err){}
  };
  ws.onerror = function() {
    document.getElementById('statusDot').style.background = 'var(--red)';
    document.getElementById('statusText').textContent = '连接断开';
  };
  ws.onclose = function() {
    document.getElementById('statusDot').style.background = '#f0a261';
    document.getElementById('statusText').textContent = '重连中...';
    setTimeout(connectBinanceWS, 3000);
  };
}

// ============================
//  RENDER ALL
// ============================
function renderAll() {
  renderCards();
  updateTicker();
}

function renderCards() {
  const grid = document.getElementById('mainGrid');
  const coins = MONITORED.filter(function(c){
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return c.symbol.toLowerCase().includes(q) || c.name.toLowerCase().includes(q) || c.id.toLowerCase().includes(q);
  });

  // Sort
  coins.sort(function(a,b){
    const da = coinData[a.id] || {};
    const db = coinData[b.id] || {};
    if (sortBy === 'rank') return (da.rank || 999) - (db.rank || 999);
    if (sortBy === 'change') return (db.change24h || 0) - (da.change24h || 0);
    if (sortBy === 'volume') return (db.volume24h || 0) - (da.volume24h || 0);
    return 0;
  });

  let html = '';
  coins.forEach(function(coin, idx){
    const d = coinData[coin.id] || {};
    const price = d.price || 0;
    const change = d.change24h || 0;
    const isUp = change >= 0;
    const changeStr = (isUp ? '+' : '') + change.toFixed(2) + '%';
    const mcapStr = formatNum(d.marketCap || 0);
    const volStr = formatNum(d.volume24h || 0);
    const rankStr = d.rank ? '#' + d.rank : '-';

    // Format price
    let priceStr;
    if (price >= 1000) priceStr = '$' + price.toLocaleString('en-US',{maximumFractionDigits:2});
    else if (price >= 1) priceStr = '$' + price.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:4});
    else if (price > 0) priceStr = '$' + price.toFixed(6);
    else priceStr = '$--';

    html += '<div class="card" data-id="' + coin.id + '" data-symbol="' + coin.symbol + '">' +
      '<div class="card-top">' +
        '<div class="coin-info">' +
          '<div class="coin-icon">' + getCoinIcon(coin.symbol) + '</div>' +
          '<div>' +
            '<div class="coin-symbol">' + coin.symbol + '</div>' +
            '<div class="coin-name">' + coin.name + '</div>' +
          '</div>' +
        '</div>' +
        '<div class="coin-rank">' + rankStr + '</div>' +
      '</div>' +
      '<div class="card-price" id="price-' + coin.id + '">' + priceStr + '</div>' +
      '<div class="card-change ' + (isUp ? 'up' : 'down') + '" id="change-' + coin.id + '">' + changeStr + '</div>' +
      '<div class="sparkline-wrap"><canvas id="spark-' + coin.id + '" width="260" height="48"></canvas></div>' +
      '<div class="card-bottom">' +
        '<span><span class="lbl">市值</span><span class="val">' + mcapStr + '</span></span>' +
        '<span><span class="lbl">24h 交易量</span><span class="val">' + volStr + '</span></span>' +
      '</div>' +
    '</div>';
  });

  if (coins.length === 0) {
    html = '<div class="loading" style="grid-column:1/-1"><div style="font-size:2rem;margin-bottom:8px">🔍</div><div>未找到匹配币种</div></div>';
  }

  grid.innerHTML = html;

  // Draw sparklines after DOM update
  setTimeout(function(){
    coins.forEach(function(coin){
      const d = coinData[coin.id];
      if (d && d.sparkline && d.sparkline.length > 1) {
        drawSparkline('spark-' + coin.id, d.sparkline, d.change24h >= 0);
      }
    });
  }, 50);
}

// ============================
//  TICKER TAPE
// ============================
function updateTicker() {
  const track = document.getElementById('tickerTrack');
  const items = MONITORED.map(function(c){
    const d = coinData[c.id] || {};
    const price = d.price || 0;
    const change = d.change24h || 0;
    const isUp = change >= 0;
    let pStr;
    if (price >= 1000) pStr = '$' + price.toFixed(2);
    else if (price >= 1) pStr = '$' + price.toFixed(4);
    else if (price > 0) pStr = '$' + price.toFixed(6);
    else pStr = '$--';
    return '<span class="ticker-item">' +
      '<span class="ticker-symbol">' + c.symbol + '</span>' +
      '<span class="ticker-price">' + pStr + '</span>' +
      '<span class="ticker-change ' + (isUp ? 'up' : 'down') + '">' + (isUp ? '+' : '') + change.toFixed(2) + '%</span>' +
      '</span>';
  });
  // Duplicate for seamless scroll
  track.innerHTML = items.join('') + items.join('');
  // Adjust animation speed
  const totalChars = items.join('').length;
  const duration = Math.max(totalChars * 0.02, 15);
  track.style.animationDuration = duration + 's';
}

// ============================
//  SPARKLINE (mini chart)
// ============================
function drawSparkline(canvasId, data, isUp) {
  const canvas = document.getElementById(canvasId);
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  const W = canvas.width = canvas.parentElement.clientWidth;
  const H = canvas.height = 48;
  ctx.clearRect(0, 0, W, H);

  if (data.length < 2) return;

  const min = Math.min.apply(null, data);
  const max = Math.max.apply(null, data);
  const range = max - min || 1;
  const padding = 2;

  ctx.beginPath();
  ctx.strokeStyle = isUp ? 'var(--green)' : 'var(--red)';
  ctx.lineWidth = 1.5;
  ctx.lineJoin = 'round';

  const stepX = (W - padding * 2) / (data.length - 1);
  data.forEach(function(val, i){
    const x = padding + i * stepX;
    const y = H - padding - ((val - min) / range) * (H - padding * 2);
    if (i === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  });
  ctx.stroke();

  // Gradient fill
  const grad = ctx.createLinearGradient(0, 0, 0, H);
  const color = isUp ? '38,166,154' : '239,83,80';
  grad.addColorStop(0, 'rgba(' + color + ',0.15)');
  grad.addColorStop(1, 'rgba(' + color + ',0.0)');
  ctx.lineTo(W - padding, H - padding);
  ctx.lineTo(padding, H - padding);
  ctx.closePath();
  ctx.fillStyle = grad;
  ctx.fill();
}

// ============================
//  HELPERS
// ============================
function formatNum(n) {
  if (!n || n === 0) return '$0';
  if (n >= 1e12) return '$' + (n / 1e12).toFixed(2) + 'T';
  if (n >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
  if (n >= 1e6) return '$' + (n / 1e6).toFixed(2) + 'M';
  if (n >= 1e3) return '$' + (n / 1e3).toFixed(2) + 'K';
  return '$' + n.toFixed(2);
}

function getCoinIcon(symbol) {
  const icons = {
    BTC:'₿', ETH:'Ξ', BNB:'🟡', SOL:'🟣', XRP:'💧', ADA:'🔵',
    DOGE:'🐕', AVAX:'🔺', DOT:'⭕', TRX:'♦', MATIC:'🟪',
    LINK:'🔗', UNI:'🦄', LTC:'Ł', BCH:'💚', ATOM:'⚛',
    NEAR:'🌙', APT:'🏔', ARB:'🔷', OP:'🔴', FIL:'📁',
    XLM:'⭐', HBAR:'ħ', SUI:'💧'
  };
  return icons[symbol] || symbol.charAt(0);
}

// ============================
//  EVENTS
// ============================
document.getElementById('searchInput').addEventListener('input', function(){
  searchQuery = this.value.trim();
  renderCards();
});

var sortBtns = document.querySelectorAll('.sort-btn');
sortBtns.forEach(function(btn){
  btn.addEventListener('click', function(){
    sortBtns.forEach(function(b){ b.classList.remove('active'); });
    this.classList.add('active');
    sortBy = this.getAttribute('data-sort');
    renderCards();
  });
});

// Card click opens CoinCap page
document.getElementById('mainGrid').addEventListener('click', function(e){
  var card = e.target.closest('.card');
  if (card) {
    var id = card.getAttribute('data-id');
    if (id) window.open('https://coincap.io/assets/' + id, '_blank');
  }
});

// ============================
//  COUNTDOWN TIMER
// ============================
function startCountdown() {
  if (countdownTimer) clearInterval(countdownTimer);
  refreshCountdown = 5;
  countdownTimer = setInterval(function(){
    refreshCountdown--;
    document.getElementById('countdown').textContent = refreshCountdown + 's';
    if (refreshCountdown <= 0) {
      refreshCountdown = 5;
      fetchCoinCap();
    }
  }, 1000);
}

// ============================
//  INIT
// ============================
function init() {
  fetchCoinCap();
  connectBinanceWS();
  startCountdown();
  // Background sync CoinCap every 60s
  setInterval(fetchCoinCap, 60000);
}

init();
</script>
</body>
</html>'''

