content = r'''<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>CryptoSight — 实时加密货币监控</title>
<style>
:root {
  --bg0:#0d1117;--bg1:#161b22;--bg2:#1c2333;--border:#30363d;
  --text:#e6edf3;--muted:#8b949e;--green:#26a69a;--red:#ef5350;
  --accent:#58a6ff;--accent2:#7c3aed;--radius:12px;
}
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{
  font-family:"SF Mono","JetBrains Mono","Consolas","Microsoft YaHei",monospace;
  background:var(--bg0);color:var(--text);min-height:100vh;overflow-x:hidden;
}
.header{
  background:var(--bg1);border-bottom:1px solid var(--border);
  padding:12px 20px;display:flex;align-items:center;justify-content:space-between;
  position:sticky;top:0;z-index:100;gap:12px;flex-wrap:wrap;
  backdrop-filter:blur(12px);
}
.header-left{display:flex;align-items:center;gap:10px}
.logo{font-size:1.2rem;font-weight:800;letter-spacing:1px;background:linear-gradient(135deg,var(--accent),var(--accent2));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.status-dot{width:8px;height:8px;border-radius:50%;background:var(--green);flex-shrink:0}
.status-text{font-size:.7rem;color:var(--green);white-space:nowrap}
.source-tag{font-size:.6rem;padding:2px 8px;border-radius:6px;background:var(--bg2);color:var(--muted)}
