.source-tag.fallback{color:#f0a261;border:1px solid rgba(240,162,97,.3)}
.header-right{display:flex;align-items:center;gap:8px;flex-wrap:wrap}
.search-input{
  background:var(--bg2);border:1px solid var(--border);border-radius:16px;
  padding:7px 16px 7px 32px;color:var(--text);font-size:.78rem;width:180px;
  outline:none;transition:all .25s;font-family:inherit;
}
.search-input:focus{border-color:var(--accent);width:240px}
.search-wrap{position:relative}
