  padding:6px 12px;border-radius:5px;cursor:pointer;font-size:.7rem;transition:all .2s;font-family:inherit;
}
.sort-btn:hover{color:var(--text);border-color:var(--accent)}
.sort-btn.active{background:var(--accent);color:#fff;border-color:var(--accent)}
.refresh-info{font-size:.65rem;color:var(--muted)}

/* Ticker */
.ticker-tape{background:var(--bg1);border-bottom:1px solid var(--border);overflow:hidden;padding:7px 0}
