/* Grid */
.container{max-width:1440px;margin:0 auto;padding:16px;display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px}
@media(max-width:600px){.container{grid-template-columns:1fr}}

/* Card */
.card{
  background:var(--bg1);border:1px solid var(--border);border-radius:var(--radius);
  padding:16px 18px;cursor:pointer;transition:all .25s;position:relative;overflow:hidden;
}
