.card-bottom .lbl{font-size:.6rem;text-transform:uppercase;letter-spacing:.5px}
.card-bottom .val{color:var(--text);font-weight:600}

/* States */
.toast{
  position:fixed;top:16px;left:50%;transform:translateX(-50%);z-index:500;
  background:var(--bg2);border:1px solid var(--border);border-radius:10px;
  padding:10px 20px;font-size:.75rem;box-shadow:0 8px 24px rgba(0,0,0,.5);
  animation:toastIn .3s ease,toastOut .3s ease 3.5s forwards;
  display:flex;align-items:center;gap:8px;
}
@keyframes toastIn{from{opacity:0;transform:translateX(-50%) translateY(-10px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}
@keyframes toastOut{from{opacity:1}to{opacity:0}}
.toast.warn{border-color:rgba(240,162,97,.4)}
.toast.error{border-color:rgba(239,83,80,.4)}
