.error-banner{
  background:rgba(239,83,80,.1);border:1px solid rgba(239,83,80,.2);
  border-radius:var(--radius);padding:14px 18px;margin-bottom:16px;
  font-size:.75rem;color:var(--red);grid-column:1/-1;text-align:center;
}
.footer{text-align:center;padding:20px;color:var(--muted);font-size:.68rem;border-top:1px solid var(--border);margin-top:16px}
.footer a{color:var(--accent)}
</style>
</head>
<body>

<header class="header">
  <div class="header-left">
    <div class="status-dot" id="sDot"></div>
    <span class="logo">CryptoSight</span>
    <span class="source-tag live" id="srcTag">Binance</span>
    <span class="status-text" id="sText">初始化...</span>
  </div>
  <div class="header-right">
    <div class="search-wrap">
      <input class="search-input" id="search" placeholder="搜索币种..." autocomplete="off">
    </div>
    <div class="sort-group">
      <button class="sort-btn active" data-sort="rank">排名</button>
      <button class="sort-btn" data-sort="change">涨跌</button>
      <button class="sort-btn" data-sort="volume">交易量</button>
    </div>
    <span class="refresh-info" id="refreshInfo">--</span>
  </div>
</header>

<div class="ticker-tape" id="tape"><div class="ticker-track" id="tTrack"></div></div>
<div class="container" id="grid">
  <div class="loading-state"><div class="pulse"></div><div>正在连接行情数据...</div></div>
</div>
<div class="footer">
  CryptoSight · 数据源 Binance / CoinCap / CoinGecko · 仅供参考
</div>

<script>
// =========================
//  CONFIG - 24 coins
// =========================
const COINS = [
  { s:'BTC',  n:'Bitcoin',           bn:'BTCUSDT', cg:'bitcoin',      cc:'bitcoin' },
  { s:'ETH',  n:'Ethereum',          bn:'ETHUSDT', cg:'ethereum',     cc:'ethereum' },
  { s:'BNB',  n:'BNB',               bn:'BNBUSDT', cg:'binancecoin',  cc:'tether' },
  { s:'SOL',  n:'Solana',            bn:'SOLUSDT', cg:'solana',       cc:'solana' },
  { s:'XRP',  n:'XRP',               bn:'XRPUSDT', cg:'ripple',       cc:'xrp' },
  { s:'ADA',  n:'Cardano',           bn:'ADAUSDT', cg:'cardano',      cc:'cardano' },
  { s:'DOGE', n:'Dogecoin',          bn:'DOGEUSDT',cg:'dogecoin',     cc:'dogecoin' },
  { s:'AVAX', n:'Avalanche',         bn:'AVAXUSDT',cg:'avalanche-2',  cc:'avalanche' },
  { s:'DOT',  n:'Polkadot',          bn:'DOTUSDT', cg:'polkadot',     cc:'polkadot' },
  { s:'TRX',  n:'TRON',              bn:'TRXUSDT', cg:'tron',         cc:'tron' },
  { s:'MATIC',n:'Polygon',           bn:'MATICUSDT',cg:'matic-network',cc:'polygon' },
  { s:'LINK', n:'Chainlink',         bn:'LINKUSDT',cg:'chainlink',    cc:'chainlink' },
  { s:'UNI',  n:'Uniswap',           bn:'UNIUSDT', cg:'uniswap',      cc:'uniswap' },
  { s:'LTC',  n:'Litecoin',          bn:'LTCUSDT', cg:'litecoin',     cc:'litecoin' },
  { s:'BCH',  n:'Bitcoin Cash',      bn:'BCHUSDT', cg:'bitcoin-cash', cc:'bitcoin-cash' },
  { s:'ATOM', n:'Cosmos',            bn:'ATOMUSDT',cg:'cosmos',       cc:'cosmos' },
  { s:'NEAR', n:'NEAR Protocol',     bn:'NEARUSDT',cg:'near',         cc:'near-protocol' },
  { s:'APT',  n:'Aptos',             bn:'APTUSDT', cg:'aptos',        cc:'aptos' },
  { s:'ARB',  n:'Arbitrum',          bn:'ARBUSDT', cg:'arbitrum',     cc:'arbitrum' },
  { s:'OP',   n:'Optimism',          bn:'OPUSDT',  cg:'optimism',     cc:'optimism' },
  { s:'FIL',  n:'Filecoin',          bn:'FILUSDT', cg:'filecoin',     cc:'filecoin' },
  { s:'XLM',  n:'Stellar',           bn:'XLMUSDT', cg:'stellar',      cc:'stellar' },
  { s:'HBAR', n:'Hedera',            bn:'HBARUSDT',cg:'hedera-hashgraph',cc:'hedera' },
  { s:'SUI',  n:'Sui',               bn:'SUIUSDT', cg:'sui',          cc:'sui' },
];

// Fallback hardcoded data (approximate prices - last resort)
const FALLBACK = {
  BTC:  {p:104000,c:-1.21},{ETH:{p:3280,c:-0.87}},{BNB:{p:720,c:-0.33}},
  SOL:  {p:172,c:2.14},   XRP:{p:2.68,c:-1.45},   ADA:{p:0.42,c:3.77},
  DOGE: {p:0.17,c:5.23},  {AVAX:{p:22.4,c:-0.92}}, DOT:{p:4.87,c:1.03},
  TRX:  {p:0.24,c:-0.56}, {MATIC:{p:0.31,c:2.88}}, LINK:{p:14.2,c:-1.22},
  UNI:  {p:7.88,c:4.12},  LTC:{p:132,c:-0.44},    BCH:{p:411,c:1.89},
  ATOM: {p:5.12,c:-2.11}, NEAR:{p:3.45,c:0.88},   APT:{p:6.23,c:-1.67},
  ARB:  {p:0.42,c:3.12},  OP:{p:1.12,c:-0.98},    FIL:{p:3.55,c:1.44},
  XLM:  {p:0.28,c:-0.33}, HBAR:{p:0.18,c:2.67},   SUI:{p:3.45,c:-0.89},
};

// State
let prices = {};
let sparklines = {};
let lastPrices = {};
let searchQ = '';
let sortBy = 'rank';
let dataSource = 'init';
let lastUpdate = 0;

// =========================
//  FETCH - multi-source with fallback
// =========================

// Strategy: Binance REST (primary, fastest) -> CoinCap -> CoinGecko -> fallback
// All fetched in parallel initially, then Binance REST polls every 3s

const BINANCE_HOSTS = [
  'https://api.binance.com',
  'https://api1.binance.com',
  'https://api2.binance.com',
  'https://api3.binance.com',
];

async function tryBinanceREST(host) {
  const symbols = JSON.stringify(COINS.map(function(c){ return c.bn; }));
  const url = host + '/api/v3/ticker/24hr?symbols=' + encodeURIComponent(symbols);
  const resp = await fetch(url);
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  const data = await resp.json();
  // Parse
  data.forEach(function(t){
    const s = t.symbol.replace('USDT','');
    const prev = prices[s] ? prices[s].price : null;
    const newPrice = parseFloat(t.lastPrice);
    prices[s] = {
      price: newPrice,
      change: parseFloat(t.priceChangePercent),
      high: parseFloat(t.highPrice),
      low: parseFloat(t.lowPrice),
      volume: parseFloat(t.quoteVolume), // USDT volume
      prevClose: parseFloat(t.prevClosePrice),
      count: parseInt(t.count),
    };
    // Track sparkline
    if (!sparklines[s]) sparklines[s] = [];
    sparklines[s].push(newPrice);
    if (sparklines[s].length > 60) sparklines[s].shift();
    // Flash detection
    if (prev !== null && prev !== newPrice) {
      lastPrices[s] = { old: prev, time: Date.now() };
    }
  });
  return true;
}

async function tryCoinCap() {
  const ids = COINS.map(function(c){ return c.cc; }).join(',');
  const resp = await fetch('https://api.coincap.io/v2/assets?ids=' + ids);
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  const json = await resp.json();
  json.data.forEach(function(a){
    const s = a.symbol;
    // Only fill if not already from Binance
    if (!prices[s]) {
      prices[s] = {
        price: parseFloat(a.priceUsd),
        change: parseFloat(a.changePercent24Hr),
        volume: parseFloat(a.volumeUsd24Hr),
        rank: parseInt(a.rank),
      };
      if (!sparklines[s]) sparklines[s] = [];
      sparklines[s].push(parseFloat(a.priceUsd));
      if (sparklines[s].length > 60) sparklines[s].shift();
    } else if (!prices[s].rank) {
      prices[s].rank = parseInt(a.rank);
    }
  });
  return true;
}

async function tryCoinGecko() {
  const ids = COINS.map(function(c){ return c.cg; }).join(',');
  const url = 'https://api.coingecko.com/api/v3/simple/price?ids=' + ids +
    '&vs_currencies=usd&include_24hr_change=true&include_24hr_vol=true&include_market_cap=true';
  const resp = await fetch(url);
  if (!resp.ok) throw new Error('HTTP ' + resp.status);
  const json = await resp.json();
  COINS.forEach(function(c){
    const d = json[c.cg];
    if (d && d.usd && !prices[c.s]) {
      prices[c.s] = {
        price: d.usd,
        change: d.usd_24h_change || 0,
        volume: d.usd_24h_vol || 0,
        marketCap: d.usd_market_cap || 0,
      };
      if (!sparklines[c.s]) sparklines[c.s] = [];
      sparklines[c.s].push(d.usd);
    }
  });
  return true;
}

async function fetchAll() {
  // Try all sources in parallel
  const results = await Promise.allSettled([
    (async function(){
      for (var i = 0; i < BINANCE_HOSTS.length; i++) {
        try { await tryBinanceREST(BINANCE_HOSTS[i]); return 'binance'; }
        catch(e){ continue; }
      }
      throw new Error('All Binance hosts failed');
    })(),
    tryCoinCap().then(function(){ return 'coincap'; }).catch(function(){ throw new Error('CoinCap failed'); }),
    tryCoinGecko().then(function(){ return 'coingecko'; }).catch(function(){ throw new Error('CoinGecko failed'); }),
  ]);

  let bestSource = 'fallback';
  for (var r = 0; r < results.length; r++) {
    if (results[r].status === 'fulfilled') {
      bestSource = results[r].value;
      break;
    }
  }

  // If no API worked, use fallback
  if (bestSource === 'fallback') {
    Object.keys(FALLBACK).forEach(function(s){
      if (!prices[s]) {
        prices[s] = {
          price: FALLBACK[s].p,
          change: FALLBACK[s].c,
          volume: FALLBACK[s].p * 1e7,
          rank: 999,
        };
      }
    });
  }

  dataSource = bestSource;
  lastUpdate = Date.now();
  updateUI();
}

// =========================
//  RENDER
// =========================
function updateUI() {
  updateStatus();
  updateTicker();
  renderCards();
}

function updateStatus() {
  var dot = document.getElementById('sDot');
  var tag = document.getElementById('srcTag');
  var txt = document.getElementById('sText');
  var elapsed = Math.floor((Date.now() - lastUpdate) / 1000);

  if (dataSource === 'binance') {
    dot.style.background = 'var(--green)';
    tag.textContent = 'Binance'; tag.className = 'source-tag live';
    txt.textContent = elapsed + 's 前更新';
  } else if (dataSource === 'coincap') {
    dot.style.background = '#f0a261';
    tag.textContent = 'CoinCap'; tag.className = 'source-tag fallback';
    txt.textContent = elapsed + 's 前更新';
  } else if (dataSource === 'coingecko') {
    dot.style.background = '#f0a261';
    tag.textContent = 'CoinGecko'; tag.className = 'source-tag fallback';
    txt.textContent = elapsed + 's 前更新';
  } else if (dataSource === 'fallback') {
    dot.style.background = 'var(--red)';
    tag.textContent = '离线数据'; tag.className = 'source-tag fallback';
    txt.textContent = 'API 不可用';
  } else {
    dot.style.background = 'var(--muted)';
    tag.textContent = '...'; tag.className = 'source-tag';
    txt.textContent = '连接中';
  }

  document.getElementById('refreshInfo').textContent =
    '更新 ' + new Date(lastUpdate).toLocaleTimeString('zh-CN');
}

function updateTicker() {
  var track = document.getElementById('tTrack');
  var items = COINS.map(function(c){
    var d = prices[c.s];
    if (!d) return '';
    var p = d.price;
    var ch = d.change || 0;
    var isUp = ch >= 0;
    var pStr;
    if (p >= 1000) pStr = '$' + p.toLocaleString('en-US',{maximumFractionDigits:2});
    else if (p >= 1) pStr = '$' + p.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:4});
    else pStr = '$' + p.toFixed(6);
    return '<span class="ticker-item"><span class="ticker-symbol">'+c.s+'</span>' +
      '<span class="ticker-price">'+pStr+'</span>' +
      '<span class="ticker-change '+(isUp?'up':'down')+'">'+(isUp?'+':'')+ch.toFixed(2)+'%</span></span>';
  }).filter(function(x){ return x; });

  if (items.length > 0) {
    track.innerHTML = items.join('') + items.join('');
    track.className = 'ticker-track anim';
  }
}

function renderCards() {
  var grid = document.getElementById('grid');
  var coins = COINS.filter(function(c){
    if (!searchQ) return true;
    var q = searchQ.toLowerCase();
    return c.s.toLowerCase().includes(q) || c.n.toLowerCase().includes(q);
  });

  coins.sort(function(a,b){
    var da = prices[a.s] || {};
    var db = prices[b.s] || {};
    if (sortBy === 'rank') return (da.rank||999) - (db.rank||999);
    if (sortBy === 'change') return (db.change||0) - (da.change||0);
    if (sortBy === 'volume') return (db.volume||0) - (da.volume||0);
    return 0;
  });

  if (coins.length === 0) {
    grid.innerHTML = '<div class="loading-state" style="grid-column:1/-1"><div style="font-size:2rem;margin-bottom:8px">🔍</div><div>无匹配结果</div></div>';
    return;
  }

  var hasData = Object.keys(prices).length > 0;
  if (!hasData) {
    grid.innerHTML = '<div class="loading-state" style="grid-column:1/-1"><div class="pulse"></div><div>正在获取数据...</div></div>';
    return;
  }

  var html = '';
  if (dataSource === 'fallback') {
    html += '<div class="error-banner">⚠️ 所有 API 端点不可达，当前显示为离线缓存数据</div>';
  }

  coins.forEach(function(c, idx){
    var d = prices[c.s];
    if (!d) return;
    var p = d.price, ch = d.change || 0;
    var isUp = ch >= 0;
    var pStr;
    if (p >= 1000) pStr = '$' + p.toLocaleString('en-US',{maximumFractionDigits:2});
    else if (p >= 1) pStr = '$' + p.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:4});
    else pStr = '$' + p.toFixed(6);

    var volStr = fmtNum(d.volume || 0);
    var mcapStr = fmtNum(d.marketCap || (d.price * 1e7));
    var rankStr = d.rank ? '#'+d.rank : '-';

    // Flash class
    var flashCls = '';
    var lp = lastPrices[c.s];
    if (lp && (Date.now() - lp.time) < 1000) {
      flashCls = lp.old < d.price ? ' flash-g' : ' flash-r';
    }

    html += '<div class="card' + flashCls + '" data-idx="' + idx + '" data-s="' + c.s + '">' +
      '<div class="card-top"><div class="coin-row">' +
        '<div class="coin-icon">' + icon(c.s) + '</div>' +
        '<div><div class="coin-sym">' + c.s + '</div><div class="coin-nm">' + c.n + '</div></div>' +
      '</div><div class="coin-rank">' + rankStr + '</div></div>' +
      '<div class="price-line">' +
        '<span class="card-price" id="pr-' + c.s + '">' + pStr + '</span>' +
        '<span class="card-change ' + (isUp ? 'up' : 'down') + '">' + (isUp ? '+' : '') + ch.toFixed(2) + '%</span>' +
      '</div>' +
      '<div class="spark-wrap"><canvas id="sp-' + c.s + '" width="260" height="44"></canvas></div>' +
      '<div class="card-bottom">' +
        '<span><span class="lbl">24h 高</span><span class="val">$' + (d.high || (p*1.02)).toFixed(2) + '</span></span>' +
        '<span><span class="lbl">24h 低</span><span class="val">$' + (d.low || (p*0.98)).toFixed(2) + '</span></span>' +
        '<span><span class="lbl">交易量</span><span class="val">' + volStr + '</span></span>' +
      '</div>' +
    '</div>';
  });

  grid.innerHTML = html;

  // Draw sparklines
  setTimeout(function(){
    coins.forEach(function(c){
      var sl = sparklines[c.s];
      if (sl && sl.length > 1) drawSpark('sp-' + c.s, sl, (prices[c.s]||{}).change >= 0);
    });
  }, 80);
}

// =========================
//  SPARKLINE
// =========================
function drawSpark(cid, data, isUp) {
  var cv = document.getElementById(cid);
  if (!cv) return;
  var ctx = cv.getContext('2d');
  var W = cv.width = cv.parentElement.clientWidth;
  var H = cv.height = 44;
  ctx.clearRect(0,0,W,H);
  if (data.length < 2) return;
  var min = Infinity, max = -Infinity;
  for (var i=0;i<data.length;i++){ if(data[i]<min)min=data[i]; if(data[i]>max)max=data[i]; }
  var range = max - min || 1;
  var pad = 2, step = (W-pad*2)/(data.length-1);
  ctx.beginPath();ctx.strokeStyle=isUp?'#26a69a':'#ef5350';ctx.lineWidth=1.5;ctx.lineJoin='round';
  data.forEach(function(v,i){
    var x=pad+i*step, y=H-pad-((v-min)/range)*(H-pad*2);
    if(i===0)ctx.moveTo(x,y); else ctx.lineTo(x,y);
  });
  ctx.stroke();
  var grad=ctx.createLinearGradient(0,0,0,H);
  var clr=isUp?'38,166,154':'239,83,80';
  grad.addColorStop(0,'rgba('+clr+',0.25)');grad.addColorStop(1,'rgba('+clr+',0)');
  ctx.lineTo(W-pad,H-pad);ctx.lineTo(pad,H-pad);ctx.closePath();
  ctx.fillStyle=grad;ctx.fill();
}

// =========================
//  HELPERS
// =========================
function fmtNum(n){if(!n)return'$0';if(n>=1e12)return'$'+(n/1e12).toFixed(2)+'T';if(n>=1e9)return'$'+(n/1e9).toFixed(2)+'B';if(n>=1e6)return'$'+(n/1e6).toFixed(2)+'M';if(n>=1e3)return'$'+(n/1e3).toFixed(2)+'K';return'$'+n.toFixed(2);}
function icon(s){var m={BTC:'₿',ETH:'Ξ',BNB:'🟡',SOL:'🟣',XRP:'💧',ADA:'🔵',DOGE:'🐕',AVAX:'🔺',DOT:'⭕',TRX:'♦',MATIC:'🟪',LINK:'🔗',UNI:'🦄',LTC:'Ł',BCH:'💚',ATOM:'⚛',NEAR:'🌙',APT:'🏔',ARB:'🔷',OP:'🔴',FIL:'📁',XLM:'⭐',HBAR:'ħ',SUI:'💧'};return m[s]||s[0];}

// =========================
//  EVENTS
// =========================
document.getElementById('search').addEventListener('input',function(){searchQ=this.value.trim();renderCards();});
var sbtns=document.querySelectorAll('.sort-btn');
sbtns.forEach(function(b){b.addEventListener('click',function(){sbtns.forEach(function(x){x.classList.remove('active')});this.classList.add('active');sortBy=this.getAttribute('data-sort');renderCards();});});
document.getElementById('grid').addEventListener('click',function(e){var c=e.target.closest('.card');if(c){var s=c.getAttribute('data-s');if(s)window.open('https://www.binance.com/en/trade/'+s+'_USDT','_blank');}});

// =========================
//  INIT + POLL
// =========================
fetchAll();
// Poll Binance REST every 5 seconds (only if binance worked)
setInterval(function(){
  if (dataSource === 'binance') {
    (async function(){
      for (var i=0;i<BINANCE_HOSTS.length;i++){
        try{await tryBinanceREST(BINANCE_HOSTS[i]);updateUI();return;}
        catch(e){continue;}
      }
    })();
  } else {
    // Fallback: retry all sources every 15s
    fetchAll();
  }
}, 5000);

// If binance is working, poll faster for price updates
setInterval(function(){
  if (dataSource === 'binance' && Object.keys(prices).length > 0) {
    updateUI();
  }
}, 2000);

// Retry full fetch every 30s if on fallback
setInterval(function(){
  if (dataSource === 'fallback') fetchAll();
}, 30000);
</script>
</body>
